import{_ as o,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Manage Invoices","description":"","frontmatter":{"title":"Manage Invoices","slug":"manage-invoices"},"headers":[],"relativePath":"account-hub/manage-invoices.md","filePath":"account-hub/manage-invoices.md"}'),r={name:"account-hub/manage-invoices.md"};function t(s,e,c,l,h,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The way you view your invoices will depend on whether your Dashboard uses Branch’s new or legacy billing experience, as well as whether you are an enterprise or self-serve customer.</p><p>An invoice will be sent via email to the billing contact of your account with details of the charge and a copy of the invoice receipt.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for managing invoices, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, attribution windows are configured under <strong>Account</strong> → <a href="./billing-invoices-new.html"><strong>Billing</strong></a>.</p></div><h2 id="self-serve-invoices" tabindex="-1">Self-serve invoices <a class="header-anchor" href="#self-serve-invoices" aria-label="Permalink to &quot;Self-serve invoices&quot;">​</a></h2><p>For <strong>self-serve</strong> customers, you can glance at your invoices through the <strong>Billing</strong> <a href="https://dashboard.branch.io/account-settings/billing" target="_blank" rel="noreferrer">tab</a> of the Branch Dashboard in the <strong>Invoice Details</strong> section. From here, you can quickly view the invoice amount and download a copy of the invoice.</p><p>After each invoice is generated, it will automatically be paid using your credit card on file.</p><p>If your billing contact is no longer at your company or you need assistance accessing copies of your invoices, please reach out to <a href="mailto:billing@branch.io" target="_blank" rel="noreferrer">billing@branch.io</a>.</p><h2 id="enterprise-invoices" tabindex="-1">Enterprise invoices <a class="header-anchor" href="#enterprise-invoices" aria-label="Permalink to &quot;Enterprise invoices&quot;">​</a></h2><p>For <strong>Enterprise</strong> customers, you can get a comprehensive view of your invoices through the <strong>Billing</strong> <a href="https://dashboard.branch.io/account-settings/billing" target="_blank" rel="noreferrer">tab</a> of the <strong>Account Settings</strong> page of the Branch Dashboard.</p><p>Here you will be able to organize your invoices by:</p><ul><li>Invoice Number</li><li>Invoice Date, Service Period, and Due Date</li><li>Invoice Balance</li><li>Whether the invoice is for multiple apps</li></ul><p>You can also download a copy of your invoice (PDF).</p><p>If you have any questions regarding your invoice, reach out to your account manager or to <a href="mailto:billing@branch.io" target="_blank" rel="noreferrer">billing@branch.io</a>.</p>',14)])])}const p=o(r,[["render",t]]);export{v as __pageData,p as default};
